}

/* ---------- 我方气泡（#007bfe 纯色实心）---------- */
:root {
  --bubble-me-bg: #007bfe;
  --bubble-me-color: #ffffff;
  --bubble-me-radius: 20px;
  --bubble-me-padding: 6px 16px;
  --bubble-me-font-size: 16px;
  --bubble-me-line-height: 1.4;

  --tail-me-url: url("https://i.postimg.cc/MGPZ63h4/IMG_2112.png");
  --tail-me-width: 20px;
  --tail-me-height: 20px;
  --tail-me-right: -8px;
  --tail-me-bottom: 0px;
  --tail-me-opacity: 1;
}

.bubble-me-custom {
  background: var(--bubble-me-bg) !important;
  color: var(--bubble-me-color) !important;
  padding: var(--bubble-me-padding) !important;
  font-size: var(--bubble-me-font-size) !important;
  line-height: var(--bubble-me-line-height) !important;
  border: none !important;
  border-radius: var(--bubble-me-radius) !important;
  position: relative !important;
  z-index: 2 !important;
}

.bubble-me-custom.single::before,
.bubble-me-custom.last::before {
  content: "";
  position: absolute;
  right: var(--tail-me-right);
  bottom: var(--tail-me-bottom);
  width: var(--tail-me-width);
  height: var(--tail-me-height);
  background-color: #007bfe !important;
  mask: var(--tail-me-url) no-repeat center/contain;
  -webkit-mask: var(--tail-me-url) no-repeat center/contain;
  opacity: var(--tail-me-opacity);
  pointer-events: none;
  z-index: 1;
}

.bubble-me-custom.first::before,
.bubble-me-custom.mid::before {
  display: none;
}

/* ---------- 对方气泡（#e9e9eb 纯色实心，黑色文字）---------- */
