}


/* ===== ios18语音消息 ===== */

/* 隐藏语音转文字按钮（不可见但可点击） */
.voice-transcription-toggle {
    opacity: 0 !important;
    pointer-events: auto !important;
    width: 20px !important;
    height: 20px !important;
}
.voice-transcription-toggle svg {
    display: none !important;
}

/* 隐藏下载按钮（不可见但可点击） */
.voice-download-btn {
    opacity: 0 !important;
    pointer-events: auto !important;
    width: 20px !important;
    height: 20px !important;
}
.voice-download-btn svg {
    display: none !important;
}

/* 播放按钮通用 */
.voice-play-btn {
    width: 28px !important;
    height: 28px !important;
    min-width: 28px !important;
    min-height: 28px !important;
    border-radius: 50% !important;
    border: none !important;
    box-shadow: none !important;
    display: flex !important;
    align-items: center !important;
    justify-content: center !important;
    flex-shrink: 0 !important;
    margin-right: 4px !important;
}
.voice-play-btn:active {
    transform: scale(0.92) !important;
    opacity: 0.8 !important;
}

/* 控件行 — 原来 translateY(10px)，改成 0 或负值往上挪 */
.voice-controls-row {
    display: flex !important;
    align-items: center !important;
    justify-content: center !important;
    gap: 4px !important;
    transform: translateY(0px) !important;   /* ← 改这里！原来是 10px */
    position: relative !important;
}

/* 波形条 */
.voice-waveform {
    flex: 1 !important;
    max-width: none !important;
    width: 100% !important;
    padding-right: 40px !important;
    box-sizing: border-box !important;
}

/* 时间戳 */
.voice-duration {
    position: absolute !important;
    right: -8px !important;
    font-size: 13px !important;
    font-weight: 500 !important;
    flex-shrink: 0 !important;
}

/* ===== 把「查看文字」按钮塞到波形条右边 ===== */
.voice-msg-me,
.voice-msg-them {
    position: relative !important;
}

.voice-transcription-toggle {
    position: absolute !important;
    right: 40px !important;
    top: 50% !important;
    transform: translateY(-50%) !important;
    opacity: 0 !important;              /* 不可见 */
    pointer-events: auto !important;    /* 但可点击 */
    z-index: 2 !important;
    width: 20px !important;
    height: 20px !important;
}

/* ===== 我方语音 ===== */
.voice-msg-me .voice-play-btn {
    background: #ffffff !important;
}
.voice-msg-me .voice-play-btn svg {
    width: 14px !important;
    height: 14px !important;
    color: #007bfe !important;
    fill: #007bfe !important;
    stroke: #007bfe !important;
}
.voice-msg-me .voice-waveform-bar {
    background: #ffffff !important;
}
.voice-msg-me .voice-duration {
    color: #ffffff !important;
}

/* ===== 对方语音 ===== */
.voice-msg-them .voice-play-btn {
    background: #333333 !important;
}
.voice-msg-them .voice-play-btn svg {
    width: 14px !important;
    height: 14px !important;
    color: #f3f3f3 !important;
    fill: #f3f3f3 !important;
    stroke: #f3f3f3 !important;
}
.voice-msg-them .voice-waveform-bar {
    background: #333333 !important;
}
.voice-msg-them .voice-duration {
    color: #333333 !important;
}
